package main

import (
	"fmt"
	"net/http"
	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookConfig holds the webhook configuration
type WebhookConfig struct {
	WebhookURL string `json:"webhook_url"`
}

// ConfigureWebhook handles POST requests to configure webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
	var config WebhookConfig

	// Parse JSON body
	if err := ctx.BodyParser(&config); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error":   "Invalid request body",
			"details": err.Error(),
		})
	}

	// Validate webhook URL
	if config.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "webhook_url is required",
		})
	}

	// Validate URL format
	_, err := validateWebhookURL(config.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "Invalid webhook URL format",
			"details": err.Error(),
		})
	}

	// Send test request to webhook URL
	if err := testWebhookURL(config.WebhookURL); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "Failed to reach webhook URL",
			"details": err.Error(),
		})
	}

	// Save configuration (in real app, save to database/file)
	// For demonstration, we'll just print it
	fmt.Printf("Webhook URL configured: %s\n", config.WebhookURL)

	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"message": "Webhook configured successfully",
		"url":     config.WebhookURL,
	})
}

// validateWebhookURL validates the format of the webhook URL
func validateWebhookURL(url string) (string, error) {
	if len(url) == 0 {
		return "", fmt.Errorf("URL cannot be empty")
	}

	// Check if URL has proper scheme
	if len(url) < 8 { // Minimum length for "http://"
		return "", fmt.Errorf("URL too short")
	}

	// Check for valid schemes
	validSchemes := []string{"http://", "https://"}
	hasValidScheme := false
	for _, scheme := range validSchemes {
		if len(url) >= len(scheme) && url[:len(scheme)] == scheme {
			hasValidScheme = true
			break
		}
	}

	if !hasValidScheme {
		return "", fmt.Errorf("URL must start with http:// or https://")
	}

	return url, nil
}

// testWebhookURL sends a GET request to test the webhook URL
func testWebhookURL(url string) error {
	// Create HTTP client with 3 second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send GET request
	resp, err := client.Get(url)
	if err != nil {
		return fmt.Errorf("request failed: %w", err)
	}
	defer resp.Body.Close()

	// Check response status
	if resp.StatusCode >= 400 {
		return fmt.Errorf("webhook returned status code: %d", resp.StatusCode)
	}

	return nil
}

func main() {
	// Create Fiber app
	app := fiber.New()

	// Configure webhook endpoint
	app.Post("/webhook", ConfigureWebhook)

	// Start server
	fmt.Println("Server starting on :8080")
	if err := app.Listen(":8080"); err != nil {
		fmt.Printf("Server error: %v\n", err)
	}
}

