package main

import (
	"fmt"
	"net/http"
	"sync"
	"time"

	"github.com/gofiber/fiber/v2"
)

type webhookConfigRequest struct {
	WebhookURL string `json:"webhook_url"`
}

type webhookConfigResponse struct {
	Success bool   `json:"success"`
	Message string `json:"message"`
}

var configuredWebhookURL string
var mu sync.Mutex

func ConfigureWebhook(ctx *fiber.Ctx) error {
	req := new(webhookConfigRequest)

	if err := ctx.BodyParser(req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(webhookConfigResponse{
			Success: false,
			Message: "Invalid JSON body",
		})
	}

	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(webhookConfigResponse{
			Success: false,
			Message: "webhook_url field is required",
		})
	}

	// Validate webhook URL by sending a GET request with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(webhookConfigResponse{
			Success: false,
			Message: fmt.Sprintf("Failed to connect to webhook URL: %v", err),
		})
	}
	defer resp.Body.Close()

	if resp.StatusCode >= 400 {
		return ctx.Status(fiber.StatusBadRequest).JSON(webhookConfigResponse{
			Success: false,
			Message: fmt.Sprintf("Webhook URL returned error status: %d", resp.StatusCode),
		})
	}

	// Save the configuration
	mu.Lock()
	configuredWebhookURL = req.WebhookURL
	mu.Unlock()

	return ctx.JSON(webhookConfigResponse{
		Success: true,
		Message: "Webhook URL configured successfully",
	})
}

func main() {
	app := fiber.New()

	app.Post("/webhook", ConfigureWebhook)

	app.Listen(":8080")
}

