package main

import (
	"fmt"
	"net/http"
	"net/url"
	"time"

	"github.com/gofiber/fiber/v2"
)

// Global variable to store the saved webhook configuration (for demonstration purposes)
var savedWebhookURL string

// webhookConfigRequest represents the expected JSON body for the webhook configuration request
type webhookConfigRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// webhookConfigResponse represents the JSON response returned after processing the webhook configuration
type webhookConfigResponse struct {
	Success bool   `json:"success"`
	Message string `json:"message,omitempty"`
}

// ConfigureWebhook handles the POST request to configure a webhook URL
// It validates the URL by sending a test GET request with a 3-second timeout
// and saves the configuration if validation passes
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse the request body into the webhookConfigRequest struct
	var req webhookConfigRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.JSON(webhookConfigResponse{
			Success: false,
			Message: "Invalid request body: " + err.Error(),
		})
	}

	// Validate that the webhook_url field is provided
	if req.WebhookURL == "" {
		return ctx.JSON(webhookConfigResponse{
			Success: false,
			Message: "webhook_url is required",
		})
	}

	// Validate the URL format
	parsedURL, err := url.ParseRequestURI(req.WebhookURL)
	if err != nil {
		return ctx.JSON(webhookConfigResponse{
			Success: false,
			Message: "Invalid URL format: " + err.Error(),
		})
	}

	// Check for supported URL schemes
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.JSON(webhookConfigResponse{
			Success: false,
			Message: "URL must use HTTP or HTTPS scheme",
		})
	}

	// Create an HTTP client with a 3-second timeout for validation
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send a test GET request to validate the webhook URL
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.JSON(webhookConfigResponse{
			Success: false,
			Message: "Failed to reach webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check if the response status code indicates success (2xx)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.JSON(webhookConfigResponse{
			Success: false,
			Message: fmt.Sprintf("Webhook URL returned non-success status code: %d", resp.StatusCode),
		})
	}

	// Save the configuration (in-memory for demonstration)
	savedWebhookURL = req.WebhookURL

	// Return a success response
	return ctx.JSON(webhookConfigResponse{
		Success: true,
		Message: "Webhook URL configured successfully",
	})
}

func main() {
	// Create a new Fiber application
	app := fiber.New()

	// Define the route for webhook configuration
	app.Post("/webhook", ConfigureWebhook)

	// Start the Fiber server on port 3000
	fmt.Println("Server is running on http://localhost:3000")
	if err := app.Listen(":3000"); err != nil {
		fmt.Printf("Error starting server: %v\n", err)
	}
}

