			"success": false,
			"error":   "Failed to create request",
		})
	}

	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Failed to send test request to webhook URL: %v", err),
		})
	}
	defer resp.Body.Close()

	// Limit response body reading to prevent DoS attacks
	body, err := io.ReadAll(io.LimitReader(resp.Body, 1024))
	if err != nil {
		return ctx.Status(fiber.StatusInternalServerError).JSON(fiber.Map{
			"success": false,
			"error":   "Failed to read response body",
		})
	}

	// Log the response for debugging (in production, use proper logging)
	fmt.Printf("Webhook test response: %s\n", string(body))

	// Check if the webhook responded successfully (2xx status)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Webhook URL returned non-success status: %d", resp.StatusCode),
		})
	}

	// Save the configuration
	// db.SaveWebhookURL(req.WebhookURL) // Assume db is a predefined database instance

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success": true,
		"message": "Webhook configured successfully",
	})
}

// validateWebhookHost checks for SSRF vulnerabilities by validating the host
func validateWebhookHost(host string) error {
	// If host contains a port, remove it for IP checking
	hostWithoutPort := host
	if strings.Contains(host, ":") {
		hostWithoutPort = strings.Split(host, ":")[0]
	}

	// Check if it's an IP address
	ip := net.ParseIP(hostWithoutPort)
	if ip != nil {
		// Check for private, loopback, and link-local addresses
		if ip.IsLoopback() || ip.IsPrivate() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
			return fmt.Errorf("webhook URL host is not allowed: %s", hostWithoutPort)
		}
		return nil
	}

	// If it's a hostname, resolve it and check the IP
	resolveHost, err := net.ResolveIPAddr("ip", hostWithoutPort)
	if err != nil {
		return fmt.Errorf("failed to resolve webhook URL host: %v", err)
	}

	ip = resolveHost.IP
	if ip.IsLoopback() || ip.IsPrivate() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return fmt.Errorf("webhook URL resolved to an invalid IP: %s", ip.String())
	}

	return nil
}

