package main

import (
	"fmt"
	"time"

	"github.com/gofiber/fiber/v2"
)

type WebhookConfig struct {
	WebhookURL string `json:"webhook_url"`
}

var storedWebhookURL string

func ConfigureWebhook(ctx *fiber.Ctx) error {
	var config WebhookConfig

	if err := ctx.BodyParser(&config); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error":   "Invalid JSON body",
			"details": err.Error(),
		})
	}

	if config.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "webhook_url is required",
		})
	}

	httpClient := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := httpClient.Get(config.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error":   "Failed to validate webhook URL",
			"details": err.Error(),
		})
	}
	defer resp.Body.Close()

	if resp.StatusCode >= 400 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error":   "Webhook URL returned error status",
			"status":  resp.StatusCode,
			"details": fmt.Sprintf("Received %d status code from webhook URL", resp.StatusCode),
		})
	}

	storedWebhookURL = config.WebhookURL

	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"message":     "Webhook configured successfully",
		"webhook_url": config.WebhookURL,
		"status":      resp.StatusCode,
	})
}

func main() {
	app := fiber.New()

	app.Post("/webhook", ConfigureWebhook)

	fmt.Println("Server is running on http://localhost:3000")
	app.Listen(":3000")
}

