package main

import (
	"fmt"
	"net/http"
	"net/url"
	"sync"
	"time"

	"github.com/gofiber/fiber/v2"
)

var (
	configuredWebhookURL string
	mu                   sync.RWMutex
)

func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse request body
	var requestBody struct {
		WebhookURL string `json:"webhook_url"`
	}

	if err := ctx.BodyParser(&requestBody); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "Invalid request body",
		})
	}

	// Validate webhook URL
	parsedURL, err := url.Parse(requestBody.WebhookURL)
	if err != nil || parsedURL.Scheme == "" || parsedURL.Host == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "Invalid webhook URL format",
		})
	}

	// Validate URL scheme
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "Webhook URL must use http or https scheme",
		})
	}

	// Send test request with timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	testRequest, err := http.NewRequest("GET", requestBody.WebhookURL, nil)
	if err != nil {
		return ctx.Status(fiber.StatusInternalServerError).JSON(fiber.Map{
			"error": "Failed to create test request",
		})
	}

	resp, err := client.Do(testRequest)
	if err != nil {
		return ctx.Status(fiber.StatusInternalServerError).JSON(fiber.Map{
			"error": fmt.Sprintf("Failed to reach webhook URL: %v", err),
		})
	}
	defer resp.Body.Close()

	// Check response status
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": fmt.Sprintf("Webhook returned non-success status: %d", resp.StatusCode),
		})
	}

	// Save configuration
	mu.Lock()
	configuredWebhookURL = requestBody.WebhookURL
	mu.Unlock()

	return ctx.JSON(fiber.Map{
		"status":  "success",
		"message": "Webhook configured successfully",
	})
}

func main() {
	app := fiber.New()

	app.Post("/webhook", ConfigureWebhook)

	app.Listen(":3000")
}

