// WebhookConfig represents the incoming webhook configuration request
type WebhookConfig struct {
	WebhookURL string `json:"webhook_url"`
}

// ConfigureWebhook handles POST requests to configure webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse the JSON body
	var config WebhookConfig
	if err := ctx.BodyParser(&config); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "Invalid request body",
		})
	}

	// Validate that webhook_url is provided
	if config.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "webhook_url is required",
		})
	}

	// Validate the webhook URL by sending a test GET request with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(config.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": fmt.Sprintf("Failed to reach webhook URL: %v", err),
		})
	}
	defer resp.Body.Close()

	// Check if the response status code indicates success (2xx)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": fmt.Sprintf("Webhook URL returned non-success status: %d", resp.StatusCode),
		})
	}

	// Here you would typically save the configuration to a database or file
	// For demonstration, we'll just print it
	fmt.Printf("Webhook configured successfully: %s\n", config.WebhookURL)

	// Return success response
	return ctx.JSON(fiber.Map{
		"message": "Webhook configured successfully",
		"url":     config.WebhookURL,
	})
}

func main() {
	app := fiber.New()

	// Configure the webhook endpoint
	app.Post("/webhook/configure", ConfigureWebhook)

	// Start the server
	fmt.Println("Server starting on :8080")
	if err := app.Listen(":8080"); err != nil {
		fmt.Printf("Error starting server: %v\n", err)
	}
}

