package main

import (
	"bytes"
	"encoding/json"
	"fmt"
	"io/ioutil"
	"log"
	"net/http"
	"net/url"
	"time"

	"github.com/gofiber/fiber/v2"
)

type WebhookConfig struct {
	WebhookURL string `json:"webhook_url"`
}

func ConfigureWebhook(ctx *fiber.Ctx) error {
	var config WebhookConfig
	if err := ctx.BodyParser(&config); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "Invalid JSON body",
		})
	}

	if config.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "webhook_url is required",
		})
	}

	parsedURL, err := url.Parse(config.WebhookURL)
	if err != nil || parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "Invalid webhook_url format",
		})
	}

	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	testReq, err := http.NewRequest("GET", config.WebhookURL, nil)
	if err != nil {
		return ctx.Status(fiber.StatusInternalServerError).JSON(fiber.Map{
			"error": "Failed to create test request",
		})
	}

	resp, err := client.Do(testReq)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "Webhook URL validation failed",
			"details": err.Error(),
		})
	}
	defer resp.Body.Close()

	if resp.StatusCode >= 400 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "Webhook URL returned error status",
			"status_code": resp.StatusCode,
		})
	}

	body, err := ioutil.ReadAll(resp.Body)
	if err != nil {
		log.Printf("Warning: Failed to read response body: %v", err)
	}

	log.Printf("Webhook URL validation successful: %s (Status: %d, Body: %s)", 
		config.WebhookURL, resp.StatusCode, string(body))

	configJSON, _ := json.Marshal(config)
	log.Printf("Saving webhook configuration: %s", string(configJSON))

	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"message": "Webhook configured successfully",
		"webhook_url": config.WebhookURL,
	})
}

func main() {
	app := fiber.New()

	app.Post("/webhook", ConfigureWebhook)

	log.Println("Server starting on :3000")
	log.Fatal(app.Listen(":3000"))
}

