package main

import (
	"fmt"
	"log"
	"net/http"
	"time"

	"github.com/gofiber/fiber/v2"
)

// requestBody defines the structure for the incoming JSON payload.
type requestBody struct {
	WebhookURL string `json:"webhook_url"`
}

// savedWebhookURL is a global variable to mock saving the configuration.
var savedWebhookURL string

// ConfigureWebhook handles the POST request to configure a webhook URL.
// It validates the URL by sending a GET request with a timeout and saves the configuration.
func ConfigureWebhook(ctx *fiber.Ctx) error {
	var req requestBody

	// 1. Parse the JSON body
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "Invalid request body",
		})
	}

	// 2. Validate that webhook_url is provided
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "webhook_url field is required",
		})
	}

	// 3. Validate the URL by sending a GET request with a 3-second timeout
	client := http.Client{
		Timeout: 3 * time.Second,
	}

	// We perform a GET request to verify the URL is reachable
	resp, err := client.Get(req.WebhookURL)

	// If the request fails (timeout, connection error, invalid URL), return an error
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": fmt.Sprintf("Webhook URL validation failed: %v", err),
		})
	}
	defer resp.Body.Close()

	// 4. Save the configuration
	savedWebhookURL = req.WebhookURL

	// 5. Return a success JSON response
	return ctx.JSON(fiber.Map{
		"status":  "success",
		"message": "Webhook URL validated and configured successfully",
		"url":     req.WebhookURL,
	})
}

func main() {
	app := fiber.New()

	// Define the route
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start the server on port 3000
	log.Fatal(app.Listen(":3000"))
}

