package main

import (
	"fmt"
	"net/http"
	"net/url"
	"sync"
	"time"

	"github.com/gofiber/fiber/v2"
)

// Global variable to store webhook configuration
var (
	webhookURL string
	mu         sync.Mutex
)

// WebhookRequest represents the expected JSON body structure
type WebhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// ConfigureWebhook handles POST requests to configure webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse request body
	req := new(WebhookRequest)
	if err := ctx.BodyParser(req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": "Invalid request body: " + err.Error(),
		})
	}

	// Validate webhook_url field exists and is not empty
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": "webhook_url field is required",
		})
	}

	// Validate URL format
	parsedURL, err := url.ParseRequestURI(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": "Invalid URL format: " + err.Error(),
		})
	}

	// Only allow HTTP and HTTPS protocols
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": "URL must use HTTP or HTTPS protocol",
		})
	}

	// Create HTTP client with 3-second timeout as required
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send test request to webhook URL
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusInternalServerError).JSON(fiber.Map{
			"status":  "error",
			"message": "Failed to send test request: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check if response status code indicates success (2xx)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": fmt.Sprintf("Webhook test request failed with status code: %d", resp.StatusCode),
		})
	}

	// Save the configuration (thread-safe)
	mu.Lock()
	webhookURL = req.WebhookURL
	mu.Unlock()

	// Return success response
	return ctx.JSON(fiber.Map{
		"status":  "success",
		"message": "Webhook URL configured successfully",
		"url":     req.WebhookURL,
	})
}

func main() {
	// Initialize Fiber app
	app := fiber.New()

	// Route for webhook configuration
	app.Post("/webhook/configure", ConfigureWebhook)

	// Health check endpoint (optional, for testing)
	app.Get("/health", func(ctx *fiber.Ctx) error {
		return ctx.JSON(fiber.Map{
			"status": "healthy",
		})
	})

	// Print configured webhook URL (if any)
	app.Get("/webhook/current", func(ctx *fiber.Ctx) error {
		mu.Lock()
		defer mu.Unlock()
		return ctx.JSON(fiber.Map{
			"status":     "success",
			"webhookURL": webhookURL,
		})
	})

	// Start server on port 3000
	fmt.Println("Starting server on port 3000...")
	if err := app.Listen(":3000"); err != nil {
		fmt.Printf("Error starting server: %v\n", err)
	}
}

