type WebhookConfig struct {
	WebhookURL string `json:"webhook_url"`
}

type Response struct {
	Status  string `json:"status"`
	Message string `json:"message"`
}

var httpClient = &http.Client{
	Timeout: 3 * time.Second,
}

func ConfigureWebhook(ctx *fiber.Ctx) error {
	var config WebhookConfig

	// Parse JSON body
	if err := ctx.BodyParser(&config); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Status:  "error",
			Message: "Invalid request body",
		})
	}

	// Validate webhook URL is not empty
	if config.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Status:  "error",
			Message: "Webhook URL cannot be empty",
		})
	}

	// Validate webhook URL by sending test request
	if err := validateWebhookURL(config.WebhookURL); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Status:  "error",
			Message: fmt.Sprintf("Webhook URL validation failed: %v", err),
		})
	}

	// Save configuration (simulated with logging)
	fmt.Printf("Webhook configuration saved: %s\n", config.WebhookURL)

	return ctx.Status(fiber.StatusOK).JSON(Response{
		Status:  "success",
		Message: "Webhook configured successfully",
	})
}

func validateWebhookURL(url string) error {
	// Create HTTP request with GET method
	req, err := http.NewRequest("GET", url, nil)
	if err != nil {
		return fmt.Errorf("failed to create request: %w", err)
	}

	// Send request with timeout
	resp, err := httpClient.Do(req)
	if err != nil {
		return fmt.Errorf("request failed: %w", err)
	}
	defer resp.Body.Close()

	// Check if response is successful
	if resp.StatusCode >= 200 && resp.StatusCode < 300 {
		return nil
	}

	return fmt.Errorf("unexpected status code: %d", resp.StatusCode)
}

func main() {
	// Create Fiber app
	app := fiber.New()

	// Route for webhook configuration
	app.Post("/webhook", ConfigureWebhook)

	// Start server on port 3000
	fmt.Println("Server starting on :3000")
	if err := app.Listen(":3000"); err != nil {
		fmt.Printf("Server error: %v\n", err)
	}
}

